func unaryLoggingInterceptor() grpc.UnaryServerInterceptor {
	return func(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (interface{}, error) {
		start := time.Now()
		resp, err := handler(ctx, req)
		code := status.Code(err)
		log.Printf("grpc method=%s code=%s dur=%s", info.FullMethod, code.String(), time.Since(start))
		return resp, err
	}
}

func main() {
	addr := os.Getenv("GRPC_ADDR")
	if addr == "" {
		addr = ":50051"
	}

	lis, err := net.Listen("tcp", addr)
	if err != nil {
		log.Fatalf("listen: %v", err)
	}

	grpcServer := grpc.NewServer(
		grpc.ChainUnaryInterceptor(unaryLoggingInterceptor()),
	)

	users := newUserService()
	orders := newOrderService(users)
	payments := newPaymentService(orders)

	RegisterUserServiceServer(grpcServer, users)
	RegisterOrderServiceServer(grpcServer, orders)
	RegisterPaymentServiceServer(grpcServer, payments)

	reflection.Register(grpcServer)

	errCh := make(chan error, 1)
	go func() {
		log.Printf("gRPC server listening on %s", addr)
		if err := grpcServer.Serve(lis); err != nil {
			errCh <- err
		}
	}()

	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)

	select {
	case sig := <-sigCh:
		log.Printf("signal received: %s; shutting down", sig.String())
		grpcServer.GracefulStop()
	case err := <-errCh:
		if err == nil {
			err = errors.New("server stopped")
		}
		log.Printf("server error: %v", err)
		grpcServer.Stop()
	}
}